SELECT

FROM compensatory_sync t0


    AND t0.repayment_date BETWEEN

      #{item}



    AND t0.id = #{request.id}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.business_no = #{request.businessNo}


    AND t0.business_type = #{request.businessType}


    AND t0.product_name = #{request.productName}


    AND t0.customer_name LIKE CONCAT ('%',#{request.customerName},'%')


    AND t0.sync_status = #{request.syncStatus}


    AND t0.customer_property = #{request.customerProperty}


    AND t0.credential_type = #{request.credentialType}


    AND t0.credential_no LIKE CONCAT ('%',#{request.credentialNo},'%')


    AND t0.is_first_loan_account = #{request.isFirstLoanAccount}


    AND t0.project_from = #{request.projectFrom}


    AND t0.province = #{request.province}


    AND t0.city = #{request.city}


    AND t0.area = #{request.area}


    AND t0.cooperative_bank = #{request.cooperativeBank}


    AND t0.cooperative_bank_third = #{request.cooperativeBankThird}


    AND t0.industry_gxb = #{request.industryGxb}


    AND t0.industry_jrj = #{request.industryJrj}


    AND t0.industry_gxw = #{request.industryGxw}


    AND t0.employed_population = #{request.employedPopulation}


    AND t0.total_assets = #{request.totalAssets}


    AND t0.business_revenue = #{request.businessRevenue}


    AND t0.tax_amount = #{request.taxAmount}


    AND t0.enterprise_size = #{request.enterpriseSize}


    AND t0.industry_policy_support  LIKE CONCAT('%',#{request.industryPolicySupport},'%')


    AND t0.debt_bill_start_day = #{request.debtBillStartDay}


    AND t0.debt_bill_due_day = #{request.debtBillDueDay}


    AND t0.debt_amount = #{request.debtAmount}


    AND t0.loan_rate = #{request.loanRate}


    AND t0.principle_claim_contract_no = #{request.principleClaimContractNo}


    AND t0.warranty_contract_no = #{request.warrantyContractNo}


    AND t0.guarantee_contract_no = #{request.guaranteeContractNo}


    AND t0.debt_bill_no = #{request.debtBillNo}


    AND t0.guarantee_fee_rate = #{request.guaranteeFeeRate}


    AND t0.counter_guarantee_type = #{request.counterGuaranteeType}


    AND t0.rist_type_after_guarantee = #{request.ristTypeAfterGuarantee}


    AND t0.risk_rate_bank = #{request.riskRateBank}


    AND t0.risk_rate_origin = #{request.riskRateOrigin}


    AND t0.risk_rate_again = #{request.riskRateAgain}


    AND t0.risk_rate_other = #{request.riskRateOther}


    AND t0.remark = #{request.remark}


    AND t0.relation_enterprise = #{request.relationEnterprise}


    AND t0.relation_enterprise_no = #{request.relationEnterpriseNo}


    AND t0.contact = #{request.contact}


    AND t0.tel = #{request.tel}


    AND t0.business_manager_a = #{request.businessManagerA}


    AND t0.acode = #{request.acode}


    AND t0.aname = #{request.aname}


    AND t0.assist_b = #{request.assistB}


    AND t0.bcode = #{request.bcode}


    AND t0.bname = #{request.bname}


    AND t0.repayment_date = #{request.repaymentDate}


    AND t0.repayment_bank = #{request.repaymentBank}


    AND t0.repayment_amount = #{request.repaymentAmount}


    AND t0.registered_address = #{request.registeredAddress}


    AND t0.current_address = #{request.currentAddress}


    AND t0.risk_fund = #{request.riskFund}


    AND t0.anti_remark = #{request.antiRemark}


    AND t0.related_bus_no = #{request.relatedBusNo}


    AND t0.related_guarantee_no = #{request.relatedGuaranteeNo}


    AND t0.created_dept_ids = #{request.createdDeptIds}


    AND t0.created_company_id = #{request.createdCompanyId}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
